SELECT COUNT(DISTINCT site_id)
FROM seismic_events
WHERE event_time < '2022-01-01';

SELECT COUNT(*)
FROM seismic_events
WHERE rup_mag > (
    SELECT AVG(rup_mag)
    FROM seismic_events
);
